function load$&Identity;Grid$(g) {
  var f = g.get_element().parentForm;
  if (g._rowCount > 0) g._focusWhenTabChanged();
    else try {$get(String.format('{0}_updateDlgCancel', f._id)).focus();} catch (ex) {}
  g.add_itemValueChanged(onChange$&Identity;$GridVoucherDetail$);
  g.add_commandEvent(on$&Identity;GridVoucherDetail$ExecuteCommand);
}
function scatter$&Identity;Grid$(g) {g._memvars = [];}
function dispose$GridVoucherDetail$(g) {
  try {g.remove_commandEvent(on$&Identity;GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$&Identity;$GridVoucherDetail$);} catch (ex) {}
}
function on$&Identity;GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'Check':
      var s = String.format('({0}==0)||(({1}{5}{1}<={0})&&({2}{5}{2}<={0})&&({3}{5}{3}>={0})&&({4}{5}{4}>={0}))', '[so_luong0]', '[so_luong1]', '[sl_min]', '[so_luong2]', '[sl_max]', '==0||');
      g.validRowExpression('so_luong0', s);
      break;
    default:
      break;
  }
}
function onChange$&Identity;$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, name = o.field.Name;
  switch (name) {
    case 'so_luong0':
      g.executeAggregate([['t_so_luong', 'so_luong0']]);
      break;
    default:
      break;
  }
}
function onClick$&Identity;$Calculate(o) {
  var g = o.grid, a = o.id.split('_inputCell_'), r = a[1].split('.')[0];
  if (!g) g = $find(a[0]);
  f = g.get_element().parentForm;
  var l = g._getColumnOrder('&FlowGridTagField;'), l0 = g._getColumnOrder('so_luong0'), l1 = g._getColumnOrder('sl_dh');
  var a = f.getItemValue('sl_duyet'), b = 0, c = g._getItemValue(1, l1);

  for (var i = 1; i <= g._rowCount; i++) {b = b + g._getItemValue(i, l0);}
  g._setItemValue(r, l0, o.checked ? a - (b + c): 0);
  g.executeAggregate([['t_so_luong', 'so_luong0']]);
}
